data.source_css:
.stats-bar { padding: 3rem 0; background: var(--color-surface, #f8fafc); border-top: 1px solid var(--color-border, #e2e8f0); border-bottom: 1px solid var(--color-border, #e2e8f0); }
.stats-bar__grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(140px, 1fr)); gap: 2rem; text-align: center; }
.stat__value { display: block; font-size: 2.25rem; font-weight: 800; color: var(--color-primary, #2563eb); }
.stat__label { display: block; font-size: 0.875rem; opacity: 0.65; margin-top: 0.25rem; text-transform: uppercase; letter-spacing: 0.05em; font-weight: 600; }
